import{_ as i,V as p,W as l,Y as n,Z as a,$ as t,X as e,F as o}from"./framework-2eefdab4.js";const c={},u=e('<h1 id="spring-ai-alibaba-实战-多智能体-multi-agent-系统科普与实现指南" tabindex="-1"><a class="header-anchor" href="#spring-ai-alibaba-实战-多智能体-multi-agent-系统科普与实现指南" aria-hidden="true">#</a> Spring AI Alibaba 实战：多智能体（Multi-agent）系统科普与实现指南</h1><h2 id="_1-引言" tabindex="-1"><a class="header-anchor" href="#_1-引言" aria-hidden="true">#</a> 1. 引言</h2><p>在单体智能体（Single-agent）架构中，一个 Agent 需要处理所有任务——从理解用户意图、规划步骤、调用工具到生成最终答案。随着任务复杂度的提升，这种“全能型” Agent 往往会面临<strong>上下文爆炸</strong>、<strong>工具选择困难</strong>和<strong>专业化不足</strong>等问题。</p><p><strong>多智能体（Multi-agent）系统</strong>通过将复杂任务分解为多个协同工作的专业化 Agent，有效解决了这些问题。本文将基于 Spring AI Alibaba，深入浅出地讲解 Multi-agent 的核心概念、实现模式及最佳实践，并提供完整的代码示例。</p>',4),r=n("strong",null,"本文代码示例",-1),d={href:"https://java2ai.com/docs/frameworks/agent-framework/advanced/multi-agent",target:"_blank",rel:"noopener noreferrer"},k=e(`<hr><h2 id="_2-什么是-multi-agent" tabindex="-1"><a class="header-anchor" href="#_2-什么是-multi-agent" aria-hidden="true">#</a> 2. 什么是 Multi-agent？</h2><h3 id="_2-1-核心定义" tabindex="-1"><a class="header-anchor" href="#_2-1-核心定义" aria-hidden="true">#</a> 2.1 核心定义</h3><p><strong>Multi-agent</strong> 是指由多个智能体组成的系统，这些智能体通过协作完成复杂任务。与单体智能体不同，Multi-agent 系统中的每个 Agent 通常具备特定的专业领域或职责。</p><h3 id="_2-2-与单体智能体的对比" tabindex="-1"><a class="header-anchor" href="#_2-2-与单体智能体的对比" aria-hidden="true">#</a> 2.2 与单体智能体的对比</h3><table><thead><tr><th>特性</th><th>单体智能体 (Single-agent)</th><th>多智能体 (Multi-agent)</th></tr></thead><tbody><tr><td><strong>职责</strong></td><td>全能型，处理所有任务</td><td>专业化，分工明确</td></tr><tr><td><strong>上下文</strong></td><td>所有信息集中在一个 Agent</td><td>上下文按需分配给不同 Agent</td></tr><tr><td><strong>工具数量</strong></td><td>可能过多，导致选择困难</td><td>每个 Agent 拥有少量专用工具</td></tr><tr><td><strong>扩展性</strong></td><td>随任务复杂度线性增长</td><td>通过增加 Agent 横向扩展</td></tr><tr><td><strong>适用场景</strong></td><td>简单任务、快速原型</td><td>复杂工作流、企业级应用</td></tr></tbody></table><hr><h2 id="_3-multi-agent-能解决什么问题" tabindex="-1"><a class="header-anchor" href="#_3-multi-agent-能解决什么问题" aria-hidden="true">#</a> 3. Multi-agent 能解决什么问题？</h2><h3 id="_3-1-单体智能体的局限性" tabindex="-1"><a class="header-anchor" href="#_3-1-单体智能体的局限性" aria-hidden="true">#</a> 3.1 单体智能体的局限性</h3><ol><li><strong>上下文窗口限制</strong>：长对话历史会迅速填满上下文窗口，导致模型性能下降。</li><li><strong>工具选择困难</strong>：当 Agent 拥有几十个工具时，LLM 很难准确选择最合适的工具。</li><li><strong>专业化不足</strong>：一个 Agent 难以同时精通写作、编程、数据分析等多个领域。</li><li><strong>状态管理复杂</strong>：复杂任务的状态追踪困难，容易丢失中间步骤。</li></ol><h3 id="_3-2-multi-agent-的优势" tabindex="-1"><a class="header-anchor" href="#_3-2-multi-agent-的优势" aria-hidden="true">#</a> 3.2 Multi-agent 的优势</h3><ol><li><strong>上下文隔离</strong>：每个 Agent 只关注自己需要的信息，减少上下文污染。</li><li><strong>工具精简</strong>：每个 Agent 只配备必要的工具，提高工具调用准确率。</li><li><strong>专业化分工</strong>：不同 Agent 专注不同领域，提升任务处理质量。</li><li><strong>灵活编排</strong>：通过组合不同模式（顺序、并行、路由），构建复杂工作流。</li></ol><hr><h2 id="_4-spring-ai-alibaba-中的-multi-agent-模式" tabindex="-1"><a class="header-anchor" href="#_4-spring-ai-alibaba-中的-multi-agent-模式" aria-hidden="true">#</a> 4. Spring AI Alibaba 中的 Multi-agent 模式</h2><p>Spring AI Alibaba 支持多种 Multi-agent 模式，每种模式适用于不同的场景：</p><h3 id="_4-1-顺序执行-sequential-agent" tabindex="-1"><a class="header-anchor" href="#_4-1-顺序执行-sequential-agent" aria-hidden="true">#</a> 4.1 顺序执行（Sequential Agent）</h3><p><strong>场景</strong>：任务需要按固定顺序执行，前一步的输出是后一步的输入。</p><p><strong>流程</strong>：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Agent A (处理) → 输出 → Agent B (处理) → 输出 → Agent C (最终结果)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>示例</strong>：写作工作流</p><ol><li><strong>Writer Agent</strong>：根据用户需求撰写文章</li><li><strong>Reviewer Agent</strong>：评审并修改文章</li><li><strong>Translator Agent</strong>：翻译成目标语言</li></ol><h3 id="_4-2-并行执行-parallel-agent" tabindex="-1"><a class="header-anchor" href="#_4-2-并行执行-parallel-agent" aria-hidden="true">#</a> 4.2 并行执行（Parallel Agent）</h3><p><strong>场景</strong>：多个任务可以同时进行，最后合并结果。</p><p><strong>流程</strong>：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>      ┌─ Agent A ─┐
输入 ─┼─ Agent B ─┼─ 合并输出
      └─ Agent C ─┘
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>示例</strong>：研究工作流</p><ol><li><strong>Web Research Agent</strong>：从互联网搜索信息</li><li><strong>DB Research Agent</strong>：从数据库查询信息</li><li><strong>Merge Agent</strong>：合并所有来源的数据</li></ol><h3 id="_4-3-路由模式-llmroutingagent" tabindex="-1"><a class="header-anchor" href="#_4-3-路由模式-llmroutingagent" aria-hidden="true">#</a> 4.3 路由模式（LlmRoutingAgent）</h3><p><strong>场景</strong>：根据用户输入动态选择最合适的 Agent。</p><p><strong>流程</strong>：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>用户输入 → Router Agent (LLM决策) → 选择子 Agent → 执行 → 返回结果
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>示例</strong>：客服系统</p><ul><li>用户问技术问题 →路由到 <strong>Technical Support Agent</strong></li><li>用户问账单问题 →路由到 <strong>Billing Agent</strong></li><li>用户问退货问题 →路由到 <strong>Return Agent</strong></li></ul><h3 id="_4-4-监督者模式-supervisoragent" tabindex="-1"><a class="header-anchor" href="#_4-4-监督者模式-supervisoragent" aria-hidden="true">#</a> 4.4 监督者模式（SupervisorAgent）</h3><p><strong>场景</strong>：复杂多步骤任务，需要动态决策下一步执行哪个 Agent。</p><p><strong>流程</strong>：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>用户输入 → Supervisor Agent → 选择子 Agent → 执行 → 返回 Supervisor → 决策下一步...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>示例</strong>：内容处理工作流</p><ol><li>Supervisor 接收&quot;写一篇关于春天的文章并翻译成英文&quot;</li><li>路由到 Writer Agent 写文章</li><li>Writer 完成后返回 Supervisor</li><li>Supervisor 路由到 Translator Agent 翻译</li><li>返回最终结果</li></ol><hr><h2 id="_5-技术实现-基于-spring-ai-alibaba" tabindex="-1"><a class="header-anchor" href="#_5-技术实现-基于-spring-ai-alibaba" aria-hidden="true">#</a> 5. 技术实现：基于 Spring AI Alibaba</h2><h3 id="_5-1-项目依赖" tabindex="-1"><a class="header-anchor" href="#_5-1-项目依赖" aria-hidden="true">#</a> 5.1 项目依赖</h3><p>首先在 <code>pom.xml</code> 中引入 Spring AI Alibaba 依赖：</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependencies</span><span class="token punctuation">&gt;</span></span>
    <span class="token comment">&lt;!-- Spring AI Alibaba 核心 --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>com.alibaba.cloud.ai<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>spring-ai-alibaba-agent-framework<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>\${ali-version}<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>
    
    <span class="token comment">&lt;!-- Spring Boot Web --&gt;</span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.springframework.boot<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>spring-boot-starter-web<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependencies</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-2-核心概念-overallstate" tabindex="-1"><a class="header-anchor" href="#_5-2-核心概念-overallstate" aria-hidden="true">#</a> 5.2 核心概念：OverAllState</h3><p>在 Multi-agent 系统中，<strong>OverAllState</strong> 是贯穿所有 Agent 的共享状态容器。它存储了对话历史、中间结果和全局变量。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>// OverAllState 自动管理，无需手动创建
// Agent 通过 outputKey 将输出存入状态
// 后续 Agent 通过占位符 {key} 引用状态中的值
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-3-instruction-占位符" tabindex="-1"><a class="header-anchor" href="#_5-3-instruction-占位符" aria-hidden="true">#</a> 5.3 Instruction 占位符</h3><p>Agent 之间的数据传递通过 <strong>Instruction 占位符</strong> 实现：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// 第一个 Agent：写文章</span>
<span class="token class-name">ReactAgent</span> writerAgent <span class="token operator">=</span> <span class="token class-name">ReactAgent</span><span class="token punctuation">.</span><span class="token function">builder</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">.</span><span class="token function">name</span><span class="token punctuation">(</span><span class="token string">&quot;writer_agent&quot;</span><span class="token punctuation">)</span>
    <span class="token punctuation">.</span><span class="token function">instruction</span><span class="token punctuation">(</span><span class="token string">&quot;你是一个作家，请根据用户提问写作：{input}&quot;</span><span class="token punctuation">)</span>
    <span class="token punctuation">.</span><span class="token function">outputKey</span><span class="token punctuation">(</span><span class="token string">&quot;article&quot;</span><span class="token punctuation">)</span>  <span class="token comment">// 输出存入状态，key 为 &quot;article&quot;</span>
    <span class="token punctuation">.</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 第二个 Agent：评审文章</span>
<span class="token class-name">ReactAgent</span> reviewerAgent <span class="token operator">=</span> <span class="token class-name">ReactAgent</span><span class="token punctuation">.</span><span class="token function">builder</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">.</span><span class="token function">name</span><span class="token punctuation">(</span><span class="token string">&quot;reviewer_agent&quot;</span><span class="token punctuation">)</span>
    <span class="token punctuation">.</span><span class="token function">instruction</span><span class="token punctuation">(</span><span class="token string">&quot;请评审文章：{article}&quot;</span><span class="token punctuation">)</span>  <span class="token comment">// 通过 {article} 引用前序输出</span>
    <span class="token punctuation">.</span><span class="token function">outputKey</span><span class="token punctuation">(</span><span class="token string">&quot;reviewed_article&quot;</span><span class="token punctuation">)</span>
    <span class="token punctuation">.</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在alibaba的框架中，<strong>支持的占位符</strong></p>`,51),g=n("table",null,[n("thead",null,[n("tr",null,[n("th",null,"占位符"),n("th",null,"说明"),n("th",null,"使用场景")])]),n("tbody",null,[n("tr",null,[n("td",{input:""}),n("td",null,"用户输入的原始内容"),n("td",null,"第一个Agent或需要用户输入的 Agent")]),n("tr",null,[n("td",{outputKey:""}),n("td",null,"引用其他Agent通过 outputKey 存储的输出"),n("td",null,"顺序执行中，后续Agent引用前面Agent的输出")]),n("tr",null,[n("td",{stateKey:""}),n("td",null,"引用状态中的任意键值"),n("td",null,"访问状态中的任何数据")])])],-1),v=e(`<p><strong>占位符工作原理</strong></p><p>自动替换：系统会在执行 Agent 的 instruction 时，自动将占位符替换为对应的实际值 状态查找：占位符会从当前状态（OverAllState）中查找对应的值 类型安全：占位符的值会被转换为字符串并插入到 instruction 中</p><hr><h2 id="_6-实战示例-写作与评审工作流" tabindex="-1"><a class="header-anchor" href="#_6-实战示例-写作与评审工作流" aria-hidden="true">#</a> 6. 实战示例：写作与评审工作流</h2><p>我们将实现一个<strong>顺序执行</strong>的 Multi-agent 系统：Writer Agent 负责写作，Reviewer Agent 负责评审。</p><h3 id="_6-1-创建-writer-agent" tabindex="-1"><a class="header-anchor" href="#_6-1-创建-writer-agent" aria-hidden="true">#</a> 6.1 创建 Writer Agent</h3><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">import</span> <span class="token import"><span class="token namespace">com<span class="token punctuation">.</span>alibaba<span class="token punctuation">.</span>cloud<span class="token punctuation">.</span>ai<span class="token punctuation">.</span>graph<span class="token punctuation">.</span>agent<span class="token punctuation">.</span></span><span class="token class-name">ReactAgent</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">org<span class="token punctuation">.</span>springframework<span class="token punctuation">.</span>ai<span class="token punctuation">.</span>chat<span class="token punctuation">.</span>model<span class="token punctuation">.</span></span><span class="token class-name">ChatModel</span></span><span class="token punctuation">;</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">WriterAgentFactory</span> <span class="token punctuation">{</span>
    
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token class-name">ReactAgent</span> <span class="token function">create</span><span class="token punctuation">(</span><span class="token class-name">ChatModel</span> chatModel<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token class-name">ReactAgent</span><span class="token punctuation">.</span><span class="token function">builder</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">name</span><span class="token punctuation">(</span><span class="token string">&quot;writer_agent&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">model</span><span class="token punctuation">(</span>chatModel<span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">description</span><span class="token punctuation">(</span><span class="token string">&quot;专业写作 Agent，擅长创作各类文章&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">instruction</span><span class="token punctuation">(</span><span class="token triple-quoted-string string">&quot;&quot;&quot;
                你是一位知名作家，擅长创作各类文章。
                请根据用户的提问进行回答，文章长度控制在 200 字左右。
                
                用户提问：{input}
                &quot;&quot;&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">outputKey</span><span class="token punctuation">(</span><span class="token string">&quot;article&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-2-创建-reviewer-agent" tabindex="-1"><a class="header-anchor" href="#_6-2-创建-reviewer-agent" aria-hidden="true">#</a> 6.2 创建 Reviewer Agent</h3><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">ReviewerAgentFactory</span> <span class="token punctuation">{</span>
    
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token class-name">ReactAgent</span> <span class="token function">create</span><span class="token punctuation">(</span><span class="token class-name">ChatModel</span> chatModel<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token class-name">ReactAgent</span><span class="token punctuation">.</span><span class="token function">builder</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">name</span><span class="token punctuation">(</span><span class="token string">&quot;reviewer_agent&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">model</span><span class="token punctuation">(</span>chatModel<span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">description</span><span class="token punctuation">(</span><span class="token string">&quot;专业评审 Agent，擅长修改和润色文章&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">instruction</span><span class="token punctuation">(</span><span class="token triple-quoted-string string">&quot;&quot;&quot;
                你是一位资深评论家，擅长对文章进行评审和修改。
                
                待评审文章：{article}
                
                请确保：
                1. 文章包含对西湖风景的描述
                2. 语言优美流畅
                3. 最终只返回修改后的文章，不要包含任何评论信息
                &quot;&quot;&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">outputKey</span><span class="token punctuation">(</span><span class="token string">&quot;reviewed_article&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-3-创建顺序执行工作流" tabindex="-1"><a class="header-anchor" href="#_6-3-创建顺序执行工作流" aria-hidden="true">#</a> 6.3 创建顺序执行工作流</h3><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">import</span> <span class="token import"><span class="token namespace">com<span class="token punctuation">.</span>alibaba<span class="token punctuation">.</span>cloud<span class="token punctuation">.</span>ai<span class="token punctuation">.</span>graph<span class="token punctuation">.</span>agent<span class="token punctuation">.</span>flow<span class="token punctuation">.</span>agent<span class="token punctuation">.</span></span><span class="token class-name">SequentialAgent</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>util<span class="token punctuation">.</span></span><span class="token class-name">List</span></span><span class="token punctuation">;</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">BlogWorkflowFactory</span> <span class="token punctuation">{</span>
    
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token class-name">SequentialAgent</span> <span class="token function">create</span><span class="token punctuation">(</span><span class="token class-name">ChatModel</span> chatModel<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 创建子 Agent</span>
        <span class="token class-name">ReactAgent</span> writerAgent <span class="token operator">=</span> <span class="token class-name">WriterAgentFactory</span><span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span>chatModel<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">ReactAgent</span> reviewerAgent <span class="token operator">=</span> <span class="token class-name">ReviewerAgentFactory</span><span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span>chatModel<span class="token punctuation">)</span><span class="token punctuation">;</span>
        
        <span class="token comment">// 创建顺序执行的 Multi-agent</span>
        <span class="token keyword">return</span> <span class="token class-name">SequentialAgent</span><span class="token punctuation">.</span><span class="token function">builder</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">name</span><span class="token punctuation">(</span><span class="token string">&quot;blog_workflow&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">description</span><span class="token punctuation">(</span><span class="token string">&quot;写作与评审工作流：先写文章，再评审修改&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">subAgents</span><span class="token punctuation">(</span><span class="token class-name">List</span><span class="token punctuation">.</span><span class="token function">of</span><span class="token punctuation">(</span>writerAgent<span class="token punctuation">,</span> reviewerAgent<span class="token punctuation">)</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-4-执行工作流" tabindex="-1"><a class="header-anchor" href="#_6-4-执行工作流" aria-hidden="true">#</a> 6.4 执行工作流</h3><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">import</span> <span class="token import"><span class="token namespace">com<span class="token punctuation">.</span>alibaba<span class="token punctuation">.</span>cloud<span class="token punctuation">.</span>ai<span class="token punctuation">.</span>graph<span class="token punctuation">.</span></span><span class="token class-name">OverAllState</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>util<span class="token punctuation">.</span></span><span class="token class-name">Optional</span></span><span class="token punctuation">;</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">MultiAgentDemo</span> <span class="token punctuation">{</span>
    
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// 假设已初始化 ChatModel</span>
        <span class="token class-name">ChatModel</span> chatModel <span class="token operator">=</span> <span class="token comment">/* ... */</span><span class="token punctuation">;</span>
        
        <span class="token comment">// 创建工作流</span>
        <span class="token class-name">SequentialAgent</span> workflow <span class="token operator">=</span> <span class="token class-name">BlogWorkflowFactory</span><span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span>chatModel<span class="token punctuation">)</span><span class="token punctuation">;</span>
        
        <span class="token comment">// 执行任务</span>
        <span class="token class-name">Optional</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">OverAllState</span><span class="token punctuation">&gt;</span></span> result <span class="token operator">=</span> workflow<span class="token punctuation">.</span><span class="token function">invoke</span><span class="token punctuation">(</span><span class="token string">&quot;帮我写一篇 100 字左右的西湖散文&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        
        <span class="token comment">// 处理结果</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>result<span class="token punctuation">.</span><span class="token function">isPresent</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token class-name">OverAllState</span> state <span class="token operator">=</span> result<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            
            <span class="token comment">// 访问第一个 Agent 的输出</span>
            state<span class="token punctuation">.</span><span class="token function">value</span><span class="token punctuation">(</span><span class="token string">&quot;article&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">ifPresent</span><span class="token punctuation">(</span>article <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
                <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;原始文章: &quot;</span> <span class="token operator">+</span> article<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
            
            <span class="token comment">// 访问第二个 Agent 的输出</span>
            state<span class="token punctuation">.</span><span class="token function">value</span><span class="token punctuation">(</span><span class="token string">&quot;reviewed_article&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">ifPresent</span><span class="token punctuation">(</span>reviewedArticle <span class="token operator">-&gt;</span> <span class="token punctuation">{</span>
                <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;评审后文章: &quot;</span> <span class="token operator">+</span> reviewedArticle<span class="token punctuation">)</span><span class="token punctuation">;</span>
            <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-5-运行结果示例" tabindex="-1"><a class="header-anchor" href="#_6-5-运行结果示例" aria-hidden="true">#</a> 6.5 运行结果示例</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>原始文章: 西湖，位于杭州城西，是一颗璀璨的明珠。湖水清澈见底，四周绿树成荫...
评审后文章: 西湖，位于杭州城西，是一颗璀璨的明珠。湖水清澈见底，四周绿树成荫，远处的雷峰塔倒映在水中...
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="_7-实现注意事项" tabindex="-1"><a class="header-anchor" href="#_7-实现注意事项" aria-hidden="true">#</a> 7. 实现注意事项</h2><h3 id="_7-1-上下文工程-context-engineering" tabindex="-1"><a class="header-anchor" href="#_7-1-上下文工程-context-engineering" aria-hidden="true">#</a> 7.1 上下文工程（Context Engineering）</h3><p><strong>核心原则</strong>：确保每个 Agent 只看到它需要的信息。</p><ul><li><strong>避免上下文污染</strong>：不要将所有历史记录都传递给每个 Agent</li><li><strong>合理使用 outputKey</strong>：明确每个 Agent 的输出键名</li><li><strong>控制推理内容</strong>：通过 <code>returnReasoningContents</code> 控制是否包含中间推理</li></ul><h3 id="_7-2-agent-描述的重要性" tabindex="-1"><a class="header-anchor" href="#_7-2-agent-描述的重要性" aria-hidden="true">#</a> 7.2 Agent 描述的重要性</h3><p>在路由模式（LlmRoutingAgent）中，Agent 的 <code>description</code> 至关重要：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// ✅ 好的描述：明确职责边界</span>
<span class="token punctuation">.</span><span class="token function">description</span><span class="token punctuation">(</span><span class="token string">&quot;专门处理编程问题，包括代码编写、调试、优化，擅长 Java/Python&quot;</span><span class="token punctuation">)</span>

<span class="token comment">// ❌ 不好的描述：模糊不清</span>
<span class="token punctuation">.</span><span class="token function">description</span><span class="token punctuation">(</span><span class="token string">&quot;处理各种问题&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_7-3-错误处理与重试" tabindex="-1"><a class="header-anchor" href="#_7-3-错误处理与重试" aria-hidden="true">#</a> 7.3 错误处理与重试</h3><ul><li><strong>最大迭代次数</strong>：设置合理的最大迭代次数防止无限循环</li><li><strong>异常捕获</strong>：捕获工具调用异常，返回友好错误信息</li><li><strong>状态恢复</strong>：使用 <code>MemorySaver</code> 保存状态，支持中断恢复</li></ul><h3 id="_7-4-性能优化" tabindex="-1"><a class="header-anchor" href="#_7-4-性能优化" aria-hidden="true">#</a> 7.4 性能优化</h3><ol><li><strong>并行执行</strong>：独立任务使用 ParallelAgent 并行处理</li><li><strong>缓存机制</strong>：对重复查询结果进行缓存</li><li><strong>流式输出</strong>：使用流式处理提升用户体验</li></ol><hr><h2 id="_8-扩展应用场景" tabindex="-1"><a class="header-anchor" href="#_8-扩展应用场景" aria-hidden="true">#</a> 8. 扩展应用场景</h2><h3 id="_8-1-智能客服系统" tabindex="-1"><a class="header-anchor" href="#_8-1-智能客服系统" aria-hidden="true">#</a> 8.1 智能客服系统</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Supervisor Agent
├── Technical Support Agent (技术问题)
├── Billing Agent (账单问题)
└── Return Agent (退货问题)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_8-2-数据分析工作流" tabindex="-1"><a class="header-anchor" href="#_8-2-数据分析工作流" aria-hidden="true">#</a> 8.2 数据分析工作流</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Sequential Agent
├── Data Collection Agent (数据收集)
├── Data Cleaning Agent (数据清洗)
├── Analysis Agent (数据分析)
└── Report Agent (报告生成)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_8-3-研究助手" tabindex="-1"><a class="header-anchor" href="#_8-3-研究助手" aria-hidden="true">#</a> 8.3 研究助手</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Parallel Agent
├── Web Research Agent (网络搜索)
├── Paper Research Agent (论文检索)
└── Database Agent (数据库查询)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="_9-最佳实践总结" tabindex="-1"><a class="header-anchor" href="#_9-最佳实践总结" aria-hidden="true">#</a> 9. 最佳实践总结</h2><ol><li><strong>明确职责</strong>：每个 Agent 只做一件事，做到极致</li><li><strong>合理编排</strong>：根据任务特点选择合适的模式（顺序/并行/路由）</li><li><strong>上下文隔离</strong>：通过 outputKey 和占位符控制信息流动</li><li><strong>描述清晰</strong>：为每个 Agent 编写明确的描述，便于路由决策</li><li><strong>错误处理</strong>：设置最大迭代次数，捕获异常，提供友好提示</li><li><strong>性能优化</strong>：并行执行独立任务，使用流式输出</li></ol><hr><h2 id="_10-总结" tabindex="-1"><a class="header-anchor" href="#_10-总结" aria-hidden="true">#</a> 10. 总结</h2><p>Multi-agent 系统通过专业化分工和灵活编排，有效解决了单体智能体在复杂任务中的局限性。Spring AI Alibaba 提供了丰富的 Multi-agent 模式（Sequential、Parallel、Routing、Supervisor），让开发者能够轻松构建复杂的 AI 应用。</p><p>本文的示例行对比较简单，主要是介绍了SpringAI Alibaba的Multi-Agent的相关知识点：</p><ul><li>✅ Multi-agent 的核心概念与优势</li><li>✅ Spring AI Alibaba 中的各种模式</li><li>✅ 顺序执行工作流的实现方法</li><li>✅ 上下文工程和 Agent 设计的最佳实践</li></ul><p>那么在真实的项目系统中，多Agent的写作时，如何抉择这些模式（路由还是监督者？或者简单的串行/并行？），接下来我们将以结合具体的应用场景，来演示一下如何实现要给生产可用的多Agent协作示例</p><hr><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2>`,46),m={href:"https://java2ai.com/docs/frameworks/agent-framework/advanced/multi-agent",target:"_blank",rel:"noopener noreferrer"},b={href:"https://docs.spring.io/spring-ai/reference/index.html",target:"_blank",rel:"noopener noreferrer"},h=n("hr",null,null,-1),A=n("p",null,[n("strong",null,"作者"),a("：一灰"),n("br"),n("strong",null,"日期"),a("：2026 年 3 月 15 日"),n("br"),n("strong",null,"标签"),a("：#SpringAI #Multi-agent #AI-Agent #Java #智能体协作")],-1);function _(f,x){const s=o("ExternalLinkIcon");return p(),l("div",null,[u,n("blockquote",null,[n("p",null,[r,a("基于 Spring AI Alibaba 1.0.0+ 版本，完整项目代码可参考 "),n("a",d,[a("Java2AI Multi-agent 文档"),t(s)]),a("。")])]),k,g,v,n("ul",null,[n("li",null,[n("a",m,[a("Spring AI Alibaba Multi-agent 文档"),t(s)])]),n("li",null,[n("a",b,[a("Spring AI 官方文档"),t(s)])])]),h,A])}const w=i(c,[["render",_],["__file","L05.Spring AI Alibaba 多智能体Multi-Agent介绍.html.vue"]]);export{w as default};
